#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b;
        scanf("%d %d", &a, &b);
        int s = a + b;
        if (s < 3) {
            printf("1\n");
        } else if (s <= 10) {
            printf("2\n");
        } else if (s <= 60) {
            printf("3\n");
        } else {
            printf("4\n");
        }
    }
    return 0;
}

