import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it))
        b = int(next(it))
        s = a + b
        if s < 3:
            out.append('1')
        elif s <= 10:
            out.append('2')
        elif s <= 60:
            out.append('3')
        else:
            out.append('4')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

